            spf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            spf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            spf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            spf.setNamespaceAware(true);
            spf.setXIncludeAware(false);

            XMLReader xmlReader = spf.newSAXParser().getXMLReader();
            try (StringReader stringReader = new StringReader(xmlData)) {
                SAXSource source = new SAXSource(xmlReader, new InputSource(stringReader));
                return (UserProfile) unmarshaller.unmarshal(source);
            }
        } catch (JAXBException | ParserConfigurationException | SAXException e) {
            throw new IllegalArgumentException("Failed to parse XML data into UserProfile", e);
        }
    }
}
